                                <th>Reason</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredSubscribers.map(sub => (
                                <tr key={sub.id}>
                                    <td>{formatDate(sub.dateOfApplication)}</td>
                                    <td>{sub.name}</td>
                                    <td>{sub.address}</td>
                                    <td>{sub.jobOrderNo}</td>
                                    <td>{sub.accountNumber}</td>
                                    <td>{sub.plan}</td>
                                    <td>{formatDate(sub.activationDate)}</td>
                                    <td>{sub.agent}</td>
