        const netRevenue = totalRevenue - totalPayouts - totalExpenses;

        const planDistribution = residentialPlans.map(plan => ({
            name: plan,
            value: filteredSubs.filter(sub => sub.plan === plan).length
        })).filter(p => p.value > 0);

