            status === 'Installed' ? 'var(--accent-green)' :
            status === 'Pending' ? 'var(--accent-yellow)' :
            status === 'On The Way' ? 'var(--accent-blue)' :
            status === 'Cancelled' ? 'var(--accent-red)' :
            status === 'Reject' ? 'var(--accent-gray)' :
