                                    <td style={{fontWeight: 600, color: 'var(--primary-brand)'}}>{agent.installedSales}</td>
                                    <td>{agent.totalApplications}</td>
                                    <td>{agent.conversionRate.toFixed(1)}%</td>
                                    <td>{agent.pending}</td>
                                    <td>{agent.cancelledOrRejected}</td>
