            )}

            {currentUser.role === 'agent' && (
                <div className="card" style={{ marginTop: '2rem' }}>
                    <h2>Latest Transactions</h2>
                    <div className="table-responsive-wrapper" style={{marginTop: '1rem'}}>
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Date of App.</th>
                                    <th>Name</th>
                                    <th>Plan</th>
                                    <th>Activation Date</th>
                                    <th>Status</th>
                                    <th>Payout Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                {paginatedAgentTransactionsData.items.map(sub => (
                                    <tr key={sub.id}>
                                        <td>{formatDate(sub.dateOfApplication)}</td>
                                        <td>{sub.name}</td>
                                        <td>{sub.plan}</td>
                                        <td>{formatDate(sub.activationDate)}</td>
                                        <td>
                                            <span className="status-badge" style={statusBadgeStyle(sub.status)}>
                                                {sub.status}
                                            </span>
                                        </td>
                                        <td>
                                            <span className="status-badge" style={payoutStatusBadgeStyle(sub.payoutStatus || 'Pending')}>
                                                {sub.payoutStatus || 'Pending'}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    <Pagination
                        currentPage={agentTransactionsCurrentPage}
                        totalPages={paginatedAgentTransactionsData.totalPages}
                        onPageChange={setAgentTransactionsCurrentPage}
                    />
                </div>
            )}
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';

// --- CONFIGURATION ---
// This URL should point to your deployed Google Apps Script Web App.
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxQ-PTvW5vLirBLPv5RJ_ZX0EGuDgvzkHEU8ssSBQCuecqzp0xas7g4qzwsEIxBY3lc/exec';

// --- MOCK DATA (for local development or as fallback) ---
const initialAgents = ['Ryan', 'Leah', 'Jackie', 'Lyn', 'Mhine'];

const residentialPlans = [
  'GFiber 1499 - 300Mbps',
  'GFiber 1999 - 500Mbps',
  'GFiber 2499 - 1Gbps'
];

// --- HELPERS ---
const getPlanPrice = (plan) => {
    if (!plan) return 0;
    const match = plan.match(/(\d+)/);
    return match ? parseInt(match[0], 10) : 0;
};

const calculateCommission = (plan) => {
    if (!plan) return 0;
    const price = getPlanPrice(plan);
    // Commission is 100% of the plan price (Full Commission)
    return price;
};

const formatDate = (dateString) => {
    if (!dateString) return dateString;
    const isDateOnly = /^\d{4}-\d{2}-\d{2}$/.test(dateString);
    let date;
    if (isDateOnly) {
        const parts = dateString.split('-');
        date = new Date(Date.UTC(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10)));
    } else {
        date = new Date(dateString);
    }

    if (isNaN(date.getTime())) {
        return dateString;
    }

    const options: Intl.DateTimeFormatOptions = {
        year: 'numeric',
        month: 'short',
        day: '2-digit',
        timeZone: 'UTC'
    };
    return date.toLocaleDateString('en-US', options);
};

const normalizeDateToYYYYMMDD = (sheetDate) => {
    if (!sheetDate) return '';
    const d = new Date(sheetDate);
    if (isNaN(d.getTime())) return '';

    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');

    return `${year}-${month}-${day}`;
};

const payoutStatusBadgeStyle = (status) => ({
    backgroundColor: 
        status === 'Completed' ? 'var(--accent-green)' :
        status === 'Pending' ? 'var(--accent-yellow)' :
