                </div>
            ) : (
                <div className="card-grid">
                    <div className="overview-stat-card">
                        <div className="stat-value">{visibleSubscribers.length}</div>
                        <div className="stat-label">Total Subscribers</div>
                    </div>
                    <div className="overview-stat-card">
