                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        aria-label="Search subscribers"
                        style={{maxWidth: '300px'}}
                    />
                     {currentUser.role === 'admin' && (
                        <select 
                            className="form-control"
                            value={filterAgent}
