// --- HELPERS ---
const getPlanPrice = (plan) => {
    if (!plan) return 0;
    // Ensure plan is a string to prevent .match crashes
    const planStr = String(plan);
    const match = planStr.match(/(\d+)/);
    return match ? parseInt(match[0], 10) : 0;
};

const calculateCommission = (plan) => {
    if (!plan) return 0;
    const price = getPlanPrice(plan);
    // Commission is 100% of the plan price (Full Commission)
    return price;
};

const formatDate = (dateString) => {
    if (!dateString) return dateString;
    const isDateOnly = /^\d{4}-\d{2}-\d{2}$/.test(dateString);
    let date;
    if (isDateOnly) {
        const parts = dateString.split('-');
        date = new Date(Date.UTC(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10)));
    } else {
        date = new Date(dateString);
    }

    if (isNaN(date.getTime())) {
        return dateString;
    }

    const options: Intl.DateTimeFormatOptions = {
        year: 'numeric',
        month: 'short',
        day: '2-digit',
        timeZone: 'UTC'
    };
    return date.toLocaleDateString('en-US', options);
};

const normalizeDateToYYYYMMDD = (sheetDate) => {
    if (!sheetDate) return '';
    const d = new Date(sheetDate);
    if (isNaN(d.getTime())) return '';

    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');

    return `${year}-${month}-${day}`;
};

