                            <option value="All">All Agents</option>
                            {agents.map(a => <option key={a} value={a}>{a}</option>)}
                        </select>
                    )}
                     <select 
                        className="form-control"
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        style={{maxWidth: '200px'}}
