                    </select>
                </div>
                <div className="table-responsive-wrapper">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Date of App.</th>
                                <th>Name</th>
                                <th>Address</th>
                                <th>Job Order No.</th>
                                <th>Account No.</th>
                                <th>Link</th>
                                <th>Plan</th>
                                <th>Activation Date</th>
                                <th>Agent</th>
                                <th>Encoder</th>
                                <th>Status</th>
                                <th>Reason</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredSubscribers.map(sub => (
                                <tr key={sub.id}>
                                    <td>{formatDate(sub.dateOfApplication)}</td>
