    }, [subscribers, selectedMonth, selectedYear, selectedAgent, currentUser]);

    const totalCommission = useMemo(() => reportData.reduce((sum, item) => sum + item.commission, 0), [reportData]);
    const totalSales = reportData.length;

    const handlePrint = () => {
        window.print();
