            {currentUser.role === 'agent' && (
                <div className="card" style={{ marginTop: '2rem' }}>
                    <h2>Latest Transactions</h2>
                    <div className="table-responsive-wrapper" style={{marginTop: '1rem'}}>
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Date of App.</th>
                                    <th>Name</th>
                                    <th>Plan</th>
                                    <th>Activation Date</th>
                                    <th>Status</th>
                                    <th>Payout Status</th>
                                </tr>
                            </thead>
                            <tbody>
