    useEffect(() => {
        if (subscriber) {
            setFormData({
                ...subscriber,
                activationDate: subscriber.activationDate || '' 
            });
        } else {
            setFormData(initialFormState);
        }
    }, [subscriber, isOpen, plans, agents, currentUser]);

    if (!isOpen) return null;

