        const { name, value } = e.target;
        setFormData(prev => {
            const newState = { ...prev, [name]: value };

            if (name === 'status' && value === 'Installed') {
                newState.activationDate = new Date().toISOString().split('T')[0];
            }

            if (name === 'status' && value !== 'Cancelled' && value !== 'Reject') {
                newState.reason = '';
            }

            return newState;
        });
