    };

    const [formData, setFormData] = useState(initialFormState);

    useEffect(() => {
        if (expense) {
            setFormData(expense);
        } else {
            setFormData(initialFormState);
        }
    }, [expense, isOpen]);

    if (!isOpen) return null;

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        onSave({ ...formData, amount: parseFloat(formData.amount) || 0 });
    };

    return (
        <div className="modal-backdrop">
            <div className="modal-content">
                <h2>{expense ? 'Edit Expense' : 'Add New Expense'}</h2>
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="date">Date</label>
                        <input type="date" id="date" name="date" className="form-control" value={formData.date} onChange={handleChange} required />
                    </div>
                    <div className="form-group">
                        <label htmlFor="category">Category</label>
                        <select id="category" name="category" className="form-control" value={formData.category} onChange={handleChange} required>
                            {expenseCategories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                        </select>
                    </div>
                     <div className="form-group">
                        <label htmlFor="description">Description</label>
                        <input type="text" id="description" name="description" className="form-control" value={formData.description} onChange={handleChange} required />
                    </div>
                    <div className="form-group">
                        <label htmlFor="amount">Amount</label>
                        <input type="number" id="amount" name="amount" className="form-control" value={formData.amount} onChange={handleChange} required step="0.01" />
                    </div>
                    <div className="modal-actions">
                        <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
                        <button type="submit" className="btn btn-primary">Save</button>
                    </div>
                </form>
            </div>
        </div>
    );
};


const AccountingFinancial = ({ subscribers, expenses, onSaveExpense, onDeleteExpense }) => {
    const currentYear = new Date().getFullYear();
    const currentMonth = new Date().getMonth() + 1;

    const [selectedMonth, setSelectedMonth] = useState(currentMonth);
    const [selectedYear, setSelectedYear] = useState(currentYear);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingExpense, setEditingExpense] = useState(null);

    const financialData = useMemo(() => {
        const filteredSubs = subscribers.filter(sub => {
            if (!sub.activationDate) return false;
            const activationDate = new Date(sub.activationDate);
            return sub.status === 'Installed' &&
                   activationDate.getFullYear() === selectedYear &&
                   (activationDate.getMonth() + 1) === selectedMonth;
        });

        const filteredExpenses = expenses.filter(exp => {
            if (!exp.date) return false;
            const expenseDate = new Date(exp.date);
            return expenseDate.getFullYear() === selectedYear &&
                   (expenseDate.getMonth() + 1) === selectedMonth;
        });

        const totalRevenue = filteredSubs.reduce((sum, sub) => sum + getPlanPrice(sub.plan), 0);
        const totalPayouts = filteredSubs.reduce((sum, sub) => sum + calculateCommission(sub.plan), 0);
        const totalExpenses = filteredExpenses.reduce((sum, exp) => sum + parseFloat(exp.amount || 0), 0);
        const netRevenue = totalRevenue - totalPayouts - totalExpenses;

        const planDistribution = residentialPlans.map(plan => ({
            name: plan,
            value: filteredSubs.filter(sub => sub.plan === plan).length
        })).filter(p => p.value > 0);

        return { totalRevenue, totalPayouts, totalExpenses, netRevenue, planDistribution, expensesForPeriod: filteredExpenses };
    }, [subscribers, expenses, selectedMonth, selectedYear]);

    const openModal = (expense = null) => {
        setEditingExpense(expense);
        setIsModalOpen(true);
    };
    const closeModal = () => {
        setIsModalOpen(false);
        setEditingExpense(null);
    };
    const handleSave = (expenseData) => {
        onSaveExpense(expenseData);
        closeModal();
    };
    const handleDelete = (id) => {
        if (window.confirm('Are you sure you want to delete this expense?')) {
            onDeleteExpense(id);
        }
    };

    return (
        <div>
            <h1>Accounting & Financial</h1>
            <div className="card">
                <div className="report-filters no-print">
                    <div className="form-group">
                        <label>Month</label>
                        <select className="form-control" value={selectedMonth} onChange={e => setSelectedMonth(Number(e.target.value))}>
                            {Array.from({length: 12}, (_, i) => <option key={i+1} value={i+1}>{new Date(0, i).toLocaleString('default', { month: 'long' })}</option>)}
                        </select>
                    </div>
                    <div className="form-group">
                        <label>Year</label>
                        <input className="form-control" type="number" value={selectedYear} onChange={e => setSelectedYear(Number(e.target.value))} />
                    </div>
                </div>
            </div>

            <div className="card-grid" style={{ marginTop: '2rem' }}>
                <div className="stat-card">
                    <div className="stat-value">₱{financialData.totalRevenue.toLocaleString()}</div>
                    <div className="stat-label">Total Revenue</div>
                </div>
                <div className="stat-card">
                    <div className="stat-value">₱{financialData.totalPayouts.toLocaleString()}</div>
                    <div className="stat-label">Total Payouts</div>
                </div>
                <div className="stat-card">
                    <div className="stat-value">₱{financialData.totalExpenses.toLocaleString()}</div>
                    <div className="stat-label">Total Expenses</div>
                </div>
                 <div className="stat-card">
                    <div className="stat-value" style={{color: financialData.netRevenue >= 0 ? 'var(--accent-green)' : 'var(--accent-red)'}}>
                        ₱{financialData.netRevenue.toLocaleString()}
                    </div>
                    <div className="stat-label">Net Revenue</div>
                </div>
            </div>

            <div className="card" style={{ marginTop: '2rem' }}>
                <h2>Plan Distribution</h2>
                <PieChart data={financialData.planDistribution} />
            </div>

            <div className="card" style={{ marginTop: '2rem' }}>
                <div className="page-header" style={{marginBottom: '1rem' }}>
                    <h2>Expenses Log</h2>
                    <button className="btn btn-primary no-print" onClick={() => openModal()}>Add Expense</button>
                </div>
                <div className="table-responsive-wrapper">
                    <table className="data-table report-table">
                        <thead>
                            <tr>
                                <th>Date</th>
                                <th>Category</th>
                                <th>Description</th>
                                <th>Amount</th>
                                <th className="no-print">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {financialData.expensesForPeriod.length > 0 ? financialData.expensesForPeriod.map(exp => (
                                <tr key={exp.id}>
                                    <td>{formatDate(exp.date)}</td>
                                    <td>{exp.category}</td>
                                    <td>{exp.description}</td>
                                    <td>₱{parseFloat(exp.amount || 0).toLocaleString()}</td>
                                    <td className="no-print">
                                        <div style={{ display: 'flex', gap: '0.25rem' }}>
                                            <button className="btn-icon" onClick={() => openModal(exp)} aria-label={`Edit expense`}>
                                                <Icon path="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zM20.71 7.04c.39-.39.39-1.02 0-1.41l-2.34-2.34a.9959.9959 0 00-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z" />
                                            </button>
                                            <button className="btn-icon btn-icon-danger" onClick={() => handleDelete(exp.id)} aria-label={`Delete expense`}>
                                                 <Icon path="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={5} style={{textAlign: 'center', padding: '1rem'}}>No expenses logged for this period.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
            <ExpenseModal 
                isOpen={isModalOpen}
                onClose={closeModal}
                onSave={handleSave}
                expense={editingExpense}
            />
        </div>
    );
};

const CalendarView = ({ subscribers }) => {
    const currentYear = new Date().getFullYear();
    const currentMonth = new Date().getMonth() + 1;
    const [selectedMonth, setSelectedMonth] = useState(currentMonth);
    const [selectedYear, setSelectedYear] = useState(currentYear);

    const { calendarDays, emptySlots, totalRegistered, totalInstalled } = useMemo(() => {
        const daysInMonth = new Date(selectedYear, selectedMonth, 0).getDate();
        const firstDayIndex = new Date(selectedYear, selectedMonth - 1, 1).getDay(); // 0 = Sun, 1 = Mon...

        const days = [];
        let regTotal = 0;
        let instTotal = 0;

        for (let day = 1; day <= daysInMonth; day++) {
            const dateStr = `${selectedYear}-${String(selectedMonth).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

            // Registered: based on dateOfApplication
            const registeredCount = subscribers.filter(sub => sub.dateOfApplication === dateStr).length;

            // Installed: based on activationDate and status 'Installed'
            const installedCount = subscribers.filter(sub => sub.status === 'Installed' && sub.activationDate === dateStr).length;

            regTotal += registeredCount;
            instTotal += installedCount;

            days.push({
                day,
                dateStr,
                registeredCount,
                installedCount
            });
        }

        return { 
            calendarDays: days, 
            emptySlots: firstDayIndex,
            totalRegistered: regTotal,
            totalInstalled: instTotal
        };
    }, [subscribers, selectedMonth, selectedYear]);

    const weekDays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    return (
        <div>
            <h1>Calendar</h1>
            <div className="card">
                <div className="report-filters no-print" style={{ marginBottom: '1.5rem' }}>
                     <div className="form-group">
                        <label>Month</label>
                        <select className="form-control" value={selectedMonth} onChange={e => setSelectedMonth(Number(e.target.value))}>
                            {Array.from({length: 12}, (_, i) => <option key={i+1} value={i+1}>{new Date(0, i).toLocaleString('default', { month: 'long' })}</option>)}
                        </select>
                    </div>
                    <div className="form-group">
                        <label>Year</label>
                        <input className="form-control" type="number" value={selectedYear} onChange={e => setSelectedYear(Number(e.target.value))} />
                    </div>
                </div>

                <div className="calendar-wrapper" style={{ overflowX: 'auto' }}>
                    <div style={{ 
                        display: 'grid', 
                        gridTemplateColumns: 'repeat(7, minmax(100px, 1fr))', 
                        gap: '1px', 
                        backgroundColor: 'var(--border-color)',
                        border: '1px solid var(--border-color)',
                        borderRadius: '8px',
                        overflow: 'hidden',
                        minWidth: '700px'
                    }}>
                        {/* Headers */}
                        {weekDays.map(day => (
                            <div key={day} style={{ 
                                backgroundColor: '#f9fafb', 
                                padding: '10px', 
                                textAlign: 'center', 
                                fontWeight: '600', 
                                color: 'var(--text-secondary)',
                                fontSize: '0.85rem'
                            }}>
                                {day}
                            </div>
                        ))}

                        {/* Empty Slots */}
                        {Array.from({ length: emptySlots }).map((_, i) => (
                            <div key={`empty-${i}`} style={{ backgroundColor: 'white', minHeight: '100px' }}></div>
                        ))}

                        {/* Days */}
                        {calendarDays.map(item => (
                            <div key={item.day} style={{ 
                                backgroundColor: 'white', 
                                padding: '8px', 
                                minHeight: '100px', 
                                display: 'flex', 
                                flexDirection: 'column', 
                                gap: '4px',
                                position: 'relative'
                            }}>
                                <span style={{ fontWeight: '600', fontSize: '0.9rem', color: 'var(--text-primary)' }}>{item.day}</span>

                                {(item.registeredCount > 0 || item.installedCount > 0) && (
                                    <div style={{ marginTop: 'auto', display: 'flex', flexDirection: 'column', gap: '2px', fontSize: '0.75rem' }}>
                                        {item.registeredCount > 0 && (
                                            <div style={{ 
                                                backgroundColor: 'var(--primary-brand-light)', 
                                                color: 'var(--primary-brand)', 
                                                padding: '2px 6px', 
                                                borderRadius: '4px',
                                                fontWeight: '500'
                                            }}>
                                                Registered: {item.registeredCount}
                                            </div>
                                        )}
                                        {item.installedCount > 0 && (
                                            <div style={{ 
                                                backgroundColor: '#d1fae5', 
                                                color: '#065f46', 
                                                padding: '2px 6px', 
                                                borderRadius: '4px',
                                                fontWeight: '500'
                                            }}>
                                                Installed: {item.installedCount}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>

                 <div style={{ marginTop: '20px', padding: '15px', backgroundColor: '#f3f4f6', borderRadius: '8px', display: 'flex', gap: '2rem', justifyContent: 'center', flexWrap: 'wrap' }}>
                    <div style={{textAlign: 'center'}}>
                        <div style={{fontSize: '0.85rem', color: 'var(--text-secondary)'}}>Total Registered</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 'bold', color: 'var(--primary-brand)'}}>{totalRegistered}</div>
                    </div>
                    <div style={{textAlign: 'center'}}>
                        <div style={{fontSize: '0.85rem', color: 'var(--text-secondary)'}}>Total Installed</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 'bold', color: 'var(--accent-green)'}}>{totalInstalled}</div>
                    </div>
                </div>
            </div>
        </div>
    );
};


