        const sorted = [...visibleSubscribers]
            .sort((a, b) => {
                const dateA = a.dateOfApplication ? new Date(a.dateOfApplication).getTime() : 0;
                const dateB = b.dateOfApplication ? new Date(b.dateOfApplication).getTime() : 0;
                return dateB - dateA;
