const Subscribers = ({ subscribers, onSave, onDelete, agents, plans, currentUser }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filterAgent, setFilterAgent] = useState('All');
    const [filterStatus, setFilterStatus] = useState('All');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingSubscriber, setEditingSubscriber] = useState(null);

    const visibleSubscribers = useMemo(() => {
        if (currentUser.role === 'agent') {
            return subscribers.filter(sub => sub.agent === currentUser.name);
        }
        return subscribers;
    }, [subscribers, currentUser]);

    const filteredSubscribers = useMemo(() => 
        visibleSubscribers
            .filter(sub => {
                const matchesSearch = Object.values(sub).some(val => 
                    String(val).toLowerCase().includes(searchTerm.toLowerCase())
                );
                const matchesAgent = filterAgent === 'All' || sub.agent === filterAgent;
                const matchesStatus = filterStatus === 'All' || sub.status === filterStatus;

                return matchesSearch && matchesAgent && matchesStatus;
            })
            .sort((a, b) => {
                const dateA = a.dateOfApplication ? new Date(a.dateOfApplication).getTime() : 0;
                const dateB = b.dateOfApplication ? new Date(b.dateOfApplication).getTime() : 0;
                return dateB - dateA;
            }),
        [searchTerm, visibleSubscribers, filterAgent, filterStatus]
    );

    const openModal = (subscriber = null) => {
        setEditingSubscriber(subscriber);
        setIsModalOpen(true);
    };

    const closeModal = () => {
        setIsModalOpen(false);
        setEditingSubscriber(null);
    };

    const handleSave = (subscriberData) => {
        onSave(subscriberData);
        closeModal();
    };

    const handleDelete = (id) => {
        if (window.confirm('Are you sure you want to delete this subscriber?')) {
            onDelete(id);
        }
    };

    const statusBadgeStyle = (status) => ({
        backgroundColor:
            status === 'Installed' ? 'var(--accent-green-bg)' :
            status === 'Pending' ? 'var(--accent-yellow-bg)' :
            status === 'On The Way' ? 'var(--accent-blue-bg)' :
            status === 'TRANSMITTED' ? 'var(--accent-purple-bg)' :
            status === 'with JOB Order' ? '#cffafe' :
            status === 'ONGOING' ? '#ffedd5' :
            status === 'Cancelled' ? 'var(--accent-red-bg)' :
            status === 'Reject' ? '#f3f4f6' :
            '#f3f4f6',
        color:
            status === 'Installed' ? 'var(--accent-green-text)' :
            status === 'Pending' ? 'var(--accent-yellow-text)' :
            status === 'On The Way' ? 'var(--accent-blue-text)' :
            status === 'TRANSMITTED' ? 'var(--accent-purple-text)' :
            status === 'with JOB Order' ? '#0e7490' :
            status === 'ONGOING' ? '#c2410c' :
            status === 'Cancelled' ? 'var(--accent-red-text)' :
            status === 'Reject' ? '#374151' :
            '#374151',
    });

    return (
        <div>
            <div className="page-header">
                <h1>Subscribers</h1>
                <button className="btn btn-primary" onClick={() => openModal()}>New Subscriber</button>
