const initialAgents = ['Agent A', 'Agent B', 'Agent C'];
const residentialPlans = ['Plan 1299', 'Plan 1699', 'Plan 2099', 'Plan 2499'];

// --- HELPERS ---
const normalizeDateToYYYYMMDD = (dateVal: any): string => {
    if (!dateVal) return '';
    try {
        const d = new Date(dateVal);
        if (isNaN(d.getTime())) return String(dateVal);
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    } catch {
        return String(dateVal);
    }
};

const calculateCommission = (plan: string): number => {
    const match = String(plan).match(/\d+/);
    return match ? parseInt(match[0], 10) : 0;
};

