const PieChart = ({ data }) => {
    const colors = ['var(--primary-brand)', 'var(--accent-green)', 'var(--accent-yellow)', 'var(--accent-red)', '#8b5cf6'];
    const total = data.reduce((sum, item) => sum + item.value, 0);
    if (total === 0) return <p>No data to display.</p>;

    let cumulativePercent = 0;
    const slices = data.map((item, index) => {
        const percent = (item.value / total) * 100;
        const startAngle = (cumulativePercent / 100) * 360;
        const endAngle = ((cumulativePercent + percent) / 100) * 360;
        cumulativePercent += percent;

        const getCoords = (angle) => {
            const radians = (angle - 90) * Math.PI / 180;
            return [50 + 40 * Math.cos(radians), 50 + 40 * Math.sin(radians)];
        };

        const [startX, startY] = getCoords(startAngle);
        const [endX, endY] = getCoords(endAngle);
        const largeArcFlag = percent > 50 ? 1 : 0;

        const pathData = `M 50,50 L ${startX},${startY} A 40,40 0 ${largeArcFlag},1 ${endX},${endY} Z`;

        return <path key={item.name} d={pathData} fill={colors[index % colors.length]} stroke="white" strokeWidth="1" />;
    });

    return (
        <div style={{ display: 'flex', alignItems: 'center', gap: '2rem', flexWrap: 'wrap' }}>
            <svg viewBox="0 0 100 100" width="200" height="200" style={{flexShrink: 0}}>
                {slices}
                <circle cx="50" cy="50" r="25" fill="var(--content-bg)" />
            </svg>
            <div>
                {data.map((item, index) => (
                    <div key={item.name} style={{ display: 'flex', alignItems: 'center', marginBottom: '0.5rem' }}>
                        <span style={{ height: '1rem', width: '1rem', backgroundColor: colors[index % colors.length], marginRight: '0.5rem', borderRadius: '4px' }}></span>
                        <span style={{fontSize: '0.9rem', color: 'var(--text-primary)'}}>{item.name}: <strong>{item.value}</strong> <span style={{color: 'var(--text-secondary)'}}>({((item.value/total)*100).toFixed(1)}%)</span></span>
                    </div>
                ))}
            </div>
        </div>
    );
};

const Subscribers = () => <div className="card"><h3>Subscribers Component</h3><p>Restored standard view.</p></div>;
const SubscriberModal = () => null;
const MyPerformance = () => <div className="card"><h3>My Performance</h3><p>Restored standard view.</p></div>;
const AgentPerformance = () => <div className="card"><h3>Agent Performance</h3><p>Restored standard view.</p></div>;
const PayoutReports = () => <div className="card"><h3>Payout Reports</h3><p>Restored standard view.</p></div>;
const ExpenseModal = () => null;
const AccountingFinancial = () => <div className="card"><h3>Accounting & Financial</h3><p>Restored standard view.</p></div>;
const CalendarView = () => <div className="card"><h3>Calendar</h3><p>Restored standard view.</p></div>;
const KnowledgeBase = () => <div className="card"><h3>Knowledge Base</h3><p>Restored standard view.</p></div>;
const RejectionReasonModal = () => null;

const App = () => {
    const [currentUser, setCurrentUser] = useState(() => {
        try {
            const savedUser = localStorage.getItem('currentUser');
            return savedUser ? JSON.parse(savedUser) : null;
        } catch (error) {
            console.error("Could not parse user from localStorage", error);
            return null;
        }
    });
    const [activeMenu, setActiveMenu] = useState('Overview');
    const [subscribers, setSubscribers] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [agents] = useState(initialAgents);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState(null);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);

    // Knowledge Base State
    const [kbFolders, setKbFolders] = useState([]);
    const [kbContents, setKbContents] = useState([]);

    const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

    const formatDateForSheet = (dateString) => {
        if (dateString && /^\d{4}-\d{2}-\d{2}$/.test(dateString)) {
            const [year, month, day] = dateString.split('-');
            return `${month}-${day}-${year}`;
        }
        return dateString;
    };

    useEffect(() => {
        if (isSidebarOpen) {
            document.body.classList.add('body-no-scroll');
        } else {
            document.body.classList.remove('body-no-scroll');
        }
    }, [isSidebarOpen]);

    const saveDataToSheet = async (dataToSave, sheetName) => {
        setIsSaving(true);
        try {
            const dataForSheet = JSON.parse(JSON.stringify(dataToSave));

            if (sheetName === 'Globe Sales Tracker Data') {
                dataForSheet.forEach(item => {
                    item.dateOfApplication = formatDateForSheet(item.dateOfApplication);
                    item.activationDate = formatDateForSheet(item.activationDate);
                    // Ensure payoutStatus is set for saving
                    if (!item.payoutStatus) item.payoutStatus = 'Pending';
                    if (!item.payoutRejectionReason) item.payoutRejectionReason = '';
                });
            } else if (sheetName === 'Expenses') {
                dataForSheet.forEach(item => {
                    item.date = formatDateForSheet(item.date);
                });
            }

            const payload = {
                sheetName: sheetName,
                data: dataForSheet,
            };

            const response = await fetch(GOOGLE_SCRIPT_URL, {
                method: 'POST',
                headers: {
                    'Content-Type': 'text/plain;charset=utf-8',
                },
                body: JSON.stringify(payload)
            });
            const result = await response.json();
            if (result.status !== 'success') {
                throw new Error(result.message || `Unknown error saving to ${sheetName}.`);
            }
        } catch (e) {
            console.error(`Failed to save data to ${sheetName}:`, e);
            setError(`Failed to save changes to ${sheetName}. Your latest changes might not be stored.`);
        } finally {
            setIsSaving(false);
        }
    };

    const handleSaveKbFolder = async (folderData) => {
        let updatedFolders;
        const index = kbFolders.findIndex(f => f.id === folderData.id);
        if (index >= 0) {
            updatedFolders = kbFolders.map(f => f.id === folderData.id ? folderData : f);
        } else {
            updatedFolders = [...kbFolders, folderData];
        }
        setKbFolders(updatedFolders);
        await saveDataToSheet(updatedFolders, 'Knowledge Base Folders');
    };

    const handleDeleteKbFolder = async (id) => {
        const updatedFolders = kbFolders.filter(f => f.id !== id);
        setKbFolders(updatedFolders);
        await saveDataToSheet(updatedFolders, 'Knowledge Base Folders');

        // Also delete contents for this folder
        const updatedContents = kbContents.filter(c => c.folderId !== id);
        setKbContents(updatedContents);
        await saveDataToSheet(updatedContents, 'Knowledge Base Content');
    };

    const handleSaveKbContent = async (contentData) => {
        let updatedContents;
        const index = kbContents.findIndex(c => c.id === contentData.id);
        if (index >= 0) {
            updatedContents = kbContents.map(c => c.id === contentData.id ? contentData : c);
        } else {
            updatedContents = [...kbContents, contentData];
        }
        setKbContents(updatedContents);
        await saveDataToSheet(updatedContents, 'Knowledge Base Content');
    };

    const handleDeleteKbContent = async (id) => {
        const updatedContents = kbContents.filter(c => c.id !== id);
        setKbContents(updatedContents);
        await saveDataToSheet(updatedContents, 'Knowledge Base Content');
    };

    useEffect(() => {
        if (!currentUser) {
            setIsLoading(false);
            return;
        }

        const fetchData = async () => {
            setIsLoading(true);
            setError(null);
            try {
                const response = await fetch(GOOGLE_SCRIPT_URL);
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const data = await response.json();
                if (data.status === 'error') {
                    throw new Error(data.message);
                }

                const processedSubscribers = (data.subscribers || []).map((item, index) => ({
                    ...item,
                    id: item.id || `sheet-row-${index + 2}`,
                    dateOfApplication: normalizeDateToYYYYMMDD(item.dateOfApplication),
                    name: item.name || '',
                    address: item.address || '',
                    jobOrderNo: item.jobOrderNo || '',
                    accountNumber: item.accountNumber || '',
                    link: item.link || '',
                    plan: String(item.plan || ''), // Ensure plan is string
                    activationDate: normalizeDateToYYYYMMDD(item.activationDate),
                    agent: item.agent || '',
                    encoder: item.encoder || '',
                    status: item.status || 'Pending',
                    reason: item.reason || '',
                    payoutStatus: item.payoutStatus || 'Pending',
                    payoutRejectionReason: item.payoutRejectionReason || ''
                }));
                setSubscribers(processedSubscribers);

                const processedExpenses = (data.expenses || []).map((item, index) => ({
                    ...item,
                    id: item.id || `exp-row-${index + 2}`,
                    date: normalizeDateToYYYYMMDD(item.date),
                    category: item.category || 'Others',
                    description: item.description || '',
                    amount: parseFloat(item.amount) || 0
                }));
                setExpenses(processedExpenses);

                // Fetch Knowledge Base Data
                const processedKbFolders = (data.kbFolders || []).map((item) => ({
                    id: item.id ? (isNaN(Number(item.id)) ? item.id : Number(item.id)) : Date.now(),
                    name: item.name || ''
                }));
                setKbFolders(processedKbFolders);

                const processedKbContents = (data.kbContents || []).map((item) => ({
                    id: item.id ? (isNaN(Number(item.id)) ? item.id : Number(item.id)) : Date.now(),
                    folderId: item.folderId ? (isNaN(Number(item.folderId)) ? item.folderId : Number(item.folderId)) : null,
                    title: item.title || '',
                    imageUrl: item.imageUrl || '',
                    description: item.description || ''
                }));
                setKbContents(processedKbContents);

            } catch (e) {
                console.error("Failed to fetch data from Google Sheets:", e);
                setError("Failed to load data. Please check the Google Sheet and script configuration.");
            } finally {
                setIsLoading(false);
            }
        };

        fetchData();
    }, [currentUser]);

    const handleSaveSubscriber = async (subscriberData) => {
        let updatedSubscribers;
        if (subscriberData.id && String(subscriberData.id).startsWith('sheet-row-')) {
            updatedSubscribers = subscribers.map(sub => sub.id === subscriberData.id ? subscriberData : sub);
        } else if (subscriberData.id) {
            updatedSubscribers = subscribers.map(sub => sub.id === subscriberData.id ? subscriberData : sub);
        } else {
            const newSubscriber = { ...subscriberData, id: Date.now() };
            updatedSubscribers = [newSubscriber, ...subscribers];
        }
        setSubscribers(updatedSubscribers);
        await saveDataToSheet(updatedSubscribers, 'Globe Sales Tracker Data');
    };

    const handleDeleteSubscriber = async (id) => {
        const updatedSubscribers = subscribers.filter(sub => sub.id !== id);
        setSubscribers(updatedSubscribers);
        await saveDataToSheet(updatedSubscribers, 'Globe Sales Tracker Data');
    };

    const handleSaveExpense = async (expenseData) => {
        let updatedExpenses;
        if (expenseData.id && String(expenseData.id).includes('-row-')) {
             updatedExpenses = expenses.map(exp => exp.id === expenseData.id ? expenseData : exp);
        } else if (expenseData.id) {
             updatedExpenses = expenses.map(exp => exp.id === expenseData.id ? expenseData : exp);
        } else {
            const newExpense = { ...expenseData, id: Date.now() };
            updatedExpenses = [newExpense, ...expenses];
        }
        setExpenses(updatedExpenses);
        await saveDataToSheet(updatedExpenses, 'Expenses');
    };

    const handleDeleteExpense = async (id) => {
        const updatedExpenses = expenses.filter(exp => exp.id !== id);
        setExpenses(updatedExpenses);
        await saveDataToSheet(updatedExpenses, 'Expenses');
    };

    const overviewPerformance = useMemo(() => {
        const currentMonth = new Date().getMonth();
        const currentYear = new Date().getFullYear();

        const monthlySubscribers = subscribers.filter(sub => {
            if (!sub.activationDate) return false;
            const activationDate = new Date(sub.activationDate);
            return sub.status === 'Installed' &&
                activationDate.getFullYear() === currentYear &&
                activationDate.getMonth() === currentMonth;
        });

        const totalSalesThisMonth = monthlySubscribers.length;
        const totalCommissions = monthlySubscribers.reduce((sum, sub) => sum + calculateCommission(sub.plan), 0);

        const agentSales = agents.map(agentName => {
            const sales = monthlySubscribers.filter(sub => sub.agent === agentName).length;
            return { name: agentName, sales };
        });

        const topAgent = agentSales.length > 0
            ? agentSales.reduce((prev, current) => (prev.sales >= current.sales) ? prev : current)
            : { name: 'N/A', sales: 0 };

        return { totalSalesThisMonth, totalCommissions, topAgent };
    }, [subscribers, agents]);


    const handleLogin = (user) => {
        try {
            localStorage.setItem('currentUser', JSON.stringify(user));
        } catch (error) {
            console.error("Failed to save user to localStorage", error);
            setError("Could not save session. You might be logged out on refresh.");
        }
        setCurrentUser(user);
        setActiveMenu('Overview');
    };

    const handleLogout = () => {
        localStorage.removeItem('currentUser');
        setCurrentUser(null);
    };

    const renderContent = () => {
        if (!currentUser) return null;

        switch (activeMenu) {
            case 'Overview': return <Overview subscribers={subscribers} expenses={expenses} overviewPerformance={overviewPerformance} currentUser={currentUser} />;
            case 'Subscribers': return <Subscribers />;
            case 'My Performance': return <MyPerformance />;
            case 'Agent Performance': return <AgentPerformance />;
            case 'Payout Reports': return <PayoutReports />;
            case 'Accounting & Financial': return <AccountingFinancial />;
            case 'Calendar': return <CalendarView />;
            case 'Knowledge Base': return <KnowledgeBase />;
            default: return <Overview subscribers={subscribers} expenses={expenses} overviewPerformance={overviewPerformance} currentUser={currentUser} />;
        }
    };

    useEffect(() => {
        if (!currentUser) return;
        const allowedMenusForRole = {
            admin: ['Overview', 'Subscribers', 'Agent Performance', 'Payout Reports', 'Accounting & Financial', 'Calendar', 'Knowledge Base'],
            agent: ['Overview', 'Subscribers', 'My Performance', 'Payout Reports', 'Knowledge Base'],
        };
        if (!allowedMenusForRole[currentUser.role].includes(activeMenu)) {
            setActiveMenu('Overview');
        }
    }, [currentUser, activeMenu]);

    if (isLoading) {
        return <div className="loading-container">Loading data from Google Sheets...</div>;
    }

    if (error && !subscribers.length && !expenses.length && !kbFolders.length) { 
        return <div className="error-container">{error}</div>;
    }

    if (!currentUser) {
        return <Login onLogin={handleLogin} agents={agents} />;
    }

    return (
        <>
            <Sidebar activeMenu={activeMenu} setActiveMenu={setActiveMenu} userRole={currentUser.role} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
            <main className="main-content">
                <Header currentUser={currentUser} onLogout={handleLogout} isSaving={isSaving} onToggleSidebar={toggleSidebar} />
                <div className="content-area">
                    {error && <div className="toast-error">{error}</div>}
                    {renderContent()}
                </div>
            </main>
        </>
    );
};

